class Solution {
    public boolean checkSubarraySum(int[] nums, int k) {
        Map<Integer, Integer> seen = new HashMap<>();
        seen.put(0, -1);
        int sum = 0;
        for (int i = 0; i < nums.length; i++) {
            sum += nums[i];
            if (k != 0) sum %= k;
            if (seen.containsKey(sum)) {
                if (i - seen.get(sum) > 1) return true;
            } else {
                seen.put(sum, i);
            }
        }
        return false;
    }
}
